const express = require('express');
const { BullQueue, BullQueueManager } = require('bullmq');

const app = express();
app.use(express.json());

// Initialize BullMQ queues
const queueManager = new BullQueueManager();
const highPriorityQueue = queueManager.createQueue('high-priority');
const lowPriorityQueue = queueManager.createQueue('low-priority');

// TODO: Implement job creation and retrieval endpoints

const PORT = process.env.PORT || 3000;
app.listen(PORT, () => console.log('Server running on port ' + PORT));
